package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreSurroundingSpaces() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat modified = original.withIgnoreSurroundingSpaces(true);

        assertNotNull(modified, "Modified CSVFormat should not be null");
        assertTrue(modified.getIgnoreSurroundingSpaces(), "IgnoreSurroundingSpaces should be true");
        // Original should remain unchanged (immutable)
        assertFalse(original.getIgnoreSurroundingSpaces(), "Original CSVFormat should have ignoreSurroundingSpaces false");
    }
}
